// 🍎 FatSecret API를 이용한 칼로리 정보 통합 코드

// FatSecret API 설정
const FATSECRET_CLIENT_ID = process.env.REACT_APP_FATSECRET_CLIENT_ID || 'YOUR_CLIENT_ID';
const FATSECRET_CLIENT_SECRET = process.env.REACT_APP_FATSECRET_CLIENT_SECRET || 'YOUR_CLIENT_SECRET';

// 🔑 FatSecret Access Token 가져오기
