  try {
    console.log('🔑 FatSecret Access Token 요청 시작');
    
    const credentials = btoa(`${FATSECRET_CLIENT_ID}:${FATSECRET_CLIENT_SECRET}`);
    
    const response = await fetch('https://oauth.fatsecret.com/connect/token', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': `Basic ${credentials}`
      },
      body: new URLSearchParams({
        'grant_type': 'client_credentials',
        'scope': 'basic'
      })
    });

    if (response.ok) {
      const data = await response.json();
      console.log('✅ FatSecret Access Token 획득 성공');
      return data.access_token;
    } else {
      throw new Error(`Token 요청 실패: ${response.status}`);
    }
  } catch (error) {
    console.error('❌ FatSecret Access Token 획득 실패:', error);
    throw error;
  }
};

