    };
    
    const englishName = koreanToEnglish[foodName] || foodName;
    console.log(`🌐 번역된 검색어: "${englishName}"`);
    
    const searchUrl = `https://platform.fatsecret.com/rest/server.api?method=foods.search&search_expression=${encodeURIComponent(englishName)}&format=json`;
    
    const response = await fetch(searchUrl, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${accessToken}`,
        'Content-Type': 'application/json'
      }
    });

    if (response.ok) {
      const data = await response.json();
      console.log(`✅ FatSecret 검색 성공: ${englishName}`, data);
      
      if (data.foods && data.foods.food && data.foods.food.length > 0) {
        // 첫 번째 검색 결과 사용
        const food = Array.isArray(data.foods.food) ? data.foods.food[0] : data.foods.food;
        return {
