    }
  } catch (error) {
    console.error(`❌ FatSecret 검색 오류 (${foodName}):`, error);
    return null;
  }
};

// 📊 FatSecret에서 상세 영양 정보 가져오기
const getFoodDetails = async (foodId, accessToken) => {
  try {
    console.log(`📊 FatSecret 상세 정보 요청: ${foodId}`);
    
    const detailUrl = `https://platform.fatsecret.com/rest/server.api?method=food.get&food_id=${foodId}&format=json`;
    
    const response = await fetch(detailUrl, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${accessToken}`,
        'Content-Type': 'application/json'
      }
    });

    if (response.ok) {
      const data = await response.json();
      console.log(`✅ FatSecret 상세 정보 획득 성공:`, data);
      
      if (data.food && data.food.servings && data.food.servings.serving) {
