// 🍎 종합 칼로리 정보 가져오기 함수
const getCalorieInfo = async (foodName) => {
  try {
    console.log(`🍎 칼로리 정보 조회 시작: "${foodName}"`);
    
    // 1단계: Access Token 가져오기
